import {
  AvatarRenderEngineClient,
  AvatarRenderEngineHTTPError,
} from '@/lib/avatar/avatar-render-engine-client'

type MockResponse = {
  ok: boolean
  status: number
  statusText: string
  headers: { get: (key: string) => string | null }
  json: () => Promise<unknown>
  text: () => Promise<string>
}

function mockJsonResponse(body: unknown, status: number): MockResponse {
  return {
    ok: status >= 200 && status < 300,
    status,
    statusText: status >= 200 && status < 300 ? 'OK' : 'Error',
    headers: {
      get: (key: string) => (key.toLowerCase() === 'content-type' ? 'application/json' : null),
    },
    json: async () => body,
    text: async () => JSON.stringify(body),
  }
}

function mockTextResponse(text: string, status: number, statusText?: string): MockResponse {
  return {
    ok: status >= 200 && status < 300,
    status,
    statusText: statusText || (status >= 200 && status < 300 ? 'OK' : 'Error'),
    headers: {
      get: (key: string) => (key.toLowerCase() === 'content-type' ? 'text/plain' : null),
    },
    json: async () => {
      throw new Error('Not JSON')
    },
    text: async () => text,
  }
}

describe('AvatarRenderEngineClient', () => {
  beforeEach(() => {
    jest.restoreAllMocks()
  })

  it('retries with exponential backoff on 5xx and succeeds', async () => {
    jest.useFakeTimers()
    jest.spyOn(Math, 'random').mockReturnValue(0)

    const fetchMock = jest
      .fn()
      .mockResolvedValueOnce(mockTextResponse('temporary', 500))
      .mockResolvedValueOnce(
        mockJsonResponse({ success: true, job_id: 'job-123', status: 'queued' }, 200)
      )

    // @ts-expect-error - override global fetch for test
    global.fetch = fetchMock

    const client = new AvatarRenderEngineClient({
      enabled: true,
      baseUrl: 'http://engine.test',
      baseDelayMs: 300,
      maxAttempts: 3,
      timeoutMs: 5_000,
    })

    const promise = client.createRenderJob({
      text: 'Olá',
      avatar_id: 'metahuman_01',
      preset: 'default',
      resolution: '1920x1080',
      fps: 30,
    })

    // 1º fetch acontece sem depender de timers
    await Promise.resolve()

    // backoff attempt #2 (300ms)
    await jest.advanceTimersByTimeAsync(300)

    const result = await promise
    expect(result.job_id).toBe('job-123')
    expect(fetchMock).toHaveBeenCalledTimes(2)
  })

  it('does not retry on 4xx and throws AvatarRenderEngineHTTPError', async () => {
    jest.useFakeTimers()
    jest.spyOn(Math, 'random').mockReturnValue(0)

    const fetchMock = jest
      .fn()
      .mockResolvedValue(mockTextResponse('bad request', 400, 'Bad Request'))

    // @ts-expect-error - override global fetch for test
    global.fetch = fetchMock

    const client = new AvatarRenderEngineClient({
      enabled: true,
      baseUrl: 'http://engine.test',
      maxAttempts: 3,
      timeoutMs: 5_000,
    })

    await expect(
      client.createRenderJob({
        text: 'Olá',
        avatar_id: 'metahuman_01',
      })
    ).rejects.toBeInstanceOf(AvatarRenderEngineHTTPError)

    await expect(
      client.createRenderJob({
        text: 'Olá',
        avatar_id: 'metahuman_01',
      })
    ).rejects.toMatchObject({ status: 400 })

    expect(fetchMock).toHaveBeenCalledTimes(2)
  })

  it('parses status and builds video download URL when filename exists', async () => {
    const fetchMock = jest
      .fn()
      .mockResolvedValueOnce(
        mockJsonResponse(
          {
            status: 'completed',
            progress: 100,
            video_filename: 'avatar_abc.mp4',
          },
          200
        )
      )

    // @ts-expect-error - override global fetch for test
    global.fetch = fetchMock

    const client = new AvatarRenderEngineClient({ enabled: true, baseUrl: 'http://engine.test' })
    const st = await client.getJobStatus('job-xyz')

    expect(String(st.status).toLowerCase()).toBe('completed')
    expect(st.video_filename).toBe('avatar_abc.mp4')
    expect(client.getVideoDownloadUrl('avatar_abc.mp4')).toBe(
      'http://engine.test/output/videos/avatar_abc.mp4'
    )
  })
})
